"""MKT Phase 1: Philemon, 2 John, 3 John, Jude."""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.write_text(json.dumps(data, ensure_ascii=False))
    print(f'  wrote {p.relative_to(ROOT)}')

def write_book(bookid, chapters):
    for tier, key in [('literal','L'), ('mediating','M'), ('thought','T')]:
        data = load(tier, bookid)
        for ch, verses in chapters.items():
            if ch not in data:
                data[ch] = {}
            for v, tiers in verses.items():
                data[ch][v] = tiers[key]
        save(tier, bookid, data)

# ── PHILEMON ──────────────────────────────────────────────────────────────
write_book('philemon', {
  "1": {
    "1": {"L":"Paul, a prisoner of Christ Jesus, and Timothy our brother—to Philemon our dear fellow worker,","M":"Paul, a prisoner of Christ Jesus, and Timothy our brother, To Philemon our dear friend and fellow worker—","T":"I, Paul, am writing this letter from prison for Christ Jesus. I'm joined by our brother Timothy. I'm writing to you, Philemon, our dear friend and partner in ministry—"},
    "2": {"L":"and to Apphia our sister, and to Archippus our fellow soldier, and to the church that meets in your house:","M":"also to Apphia our sister and Archippus our fellow soldier—and to the church that meets in your home:","T":"and also to our sister Apphia, to Archippus who fights alongside us, and to the whole church that gathers in your home."},
    "3": {"L":"Grace to you and peace from God our Father and the Lord Jesus Christ.","M":"Grace and peace to you from God our Father and the Lord Jesus Christ.","T":"May God our Father and the Lord Jesus Christ give you grace and peace."},
    "4": {"L":"I thank my God always, making mention of you in my prayers,","M":"I always thank my God as I remember you in my prayers,","T":"Every time I pray for you, I thank God for you."},
    "5": {"L":"hearing of your love and the faith that you have toward the Lord Jesus and for all the saints,","M":"because I hear about your love for all his holy people and your faith in the Lord Jesus.","T":"I keep hearing how much you love God's people and how strong your faith in the Lord Jesus is."},
    "6": {"L":"that the fellowship of your faith may become effective through the knowledge of every good thing that is in us for Christ.","M":"I pray that your partnership with us in the faith may be effective in deepening your understanding of every good thing we share for the sake of Christ.","T":"I pray that as you share your faith with others it will become fruitful as you come to understand every good thing that belongs to us in Christ."},
    "7": {"L":"For I have had much joy and encouragement through your love, because the hearts of the saints have been refreshed through you, brother.","M":"Your love has given me great joy and encouragement, because you, brother, have refreshed the hearts of the Lord's people.","T":"Your love has brought me great joy and encouragement, because the hearts of God's people have been refreshed through you, my brother."},
    "8": {"L":"Therefore, though I have much boldness in Christ to command you what is proper,","M":"Therefore, although in Christ I could be bold and order you to do what you ought to do,","T":"Because of our union with Christ I could order you to do what I'm about to ask—"},
    "9": {"L":"for love's sake I rather appeal to you—being such a one as Paul the aged, and now also a prisoner of Christ Jesus—","M":"yet I prefer to appeal to you on the basis of love. It is as none other than Paul—an old man and now also a prisoner of Christ Jesus—that I appeal to you","T":"but instead I choose to appeal to you simply on the basis of love. I, Paul, an old man now and a prisoner for Christ Jesus,"},
    "10": {"L":"I appeal to you concerning my child, Onesimus, whom I have fathered in my imprisonment,","M":"for my son Onesimus, who became my son while I was in chains.","T":"am appealing to you on behalf of Onesimus—my own son in the faith, born while I've been here in prison."},
    "11": {"L":"who was formerly useless to you, but is now useful both to you and to me.","M":"Formerly he was useless to you, but now he has become useful both to you and to me.","T":"In the past, as his name suggests, he was useless to you—but now he has become truly useful, both to you and to me."},
    "12": {"L":"I am sending him back to you—him, that is, my very heart.","M":"I am sending him—who is my very heart—back to you.","T":"I'm sending him back to you, and in doing so I'm sending you my own heart."},
    "13": {"L":"I wanted to keep him with me, so that he might serve me on your behalf in my chains for the gospel,","M":"I would have liked to keep him with me so that he could take your place in helping me while I am in chains for the gospel.","T":"I would have loved to keep him here to help me while I'm in chains for the gospel—he could have served in your place."},
    "14": {"L":"but I did not want to do anything without your consent, so that your goodness would not be as by compulsion but by your own free will.","M":"But I did not want to do anything without your consent, so that any favor you do would not seem forced but would be voluntary.","T":"But I didn't want to do anything without asking you first, so that whatever good you do for me will be your own free choice and not something I pressured you into."},
    "15": {"L":"For perhaps he was separated from you for a little while for this reason: so that you might have him back forever,","M":"Perhaps the reason he was separated from you for a little while was that you might have him back forever—","T":"Perhaps he was taken from you for a short time for this very reason: so you could have him back permanently—"},
    "16": {"L":"no longer as a slave, but better than a slave—as a dear brother, especially to me, and how much more to you, both in the flesh and in the Lord.","M":"no longer as a slave, but better than a slave, as a dear brother. He is very dear to me but even dearer to you, both as a fellow man and as a brother in the Lord.","T":"no longer as a slave, but as something far better—a beloved brother. He is very dear to me, but even more so to you—both as a man and as a fellow believer."},
    "17": {"L":"If therefore you regard me as a partner, receive him as you would receive me.","M":"So if you consider me a partner, welcome him as you would welcome me.","T":"If you consider me your partner, then welcome him as you would welcome me."},
    "18": {"L":"But if he has wronged you in anything or owes you anything, charge that to my account.","M":"If he has done you any wrong or owes you anything, charge it to me.","T":"If he has hurt you in any way or owes you anything, charge it to my account."},
    "19": {"L":"I, Paul, write this with my own hand: I will repay—not to mention to you that you owe me even your own self.","M":"I, Paul, am writing this with my own hand. I will pay it back—not to mention that you owe me your very self.","T":"I, Paul, am writing this personally: I will pay you back. (I won't mention, of course, that you owe me your very life!)"},
    "20": {"L":"Yes, brother, let me benefit from you in the Lord; refresh my heart in Christ.","M":"I do wish, brother, that I may have some benefit from you in the Lord; refresh my heart in Christ.","T":"So, my brother, let me have this benefit from you in the Lord. Refresh my heart in Christ."},
    "21": {"L":"Having confidence in your obedience, I write to you, knowing that you will do even more than I say.","M":"Confident of your obedience, I write to you, knowing that you will do even more than I ask.","T":"I'm writing with full confidence that you will do what I ask—in fact, I think you'll do even more."},
    "22": {"L":"And at the same time, also prepare a guest room for me, for I hope that through your prayers I will be graciously given to you.","M":"And one thing more: Prepare a guest room for me, because I hope to be restored to you in answer to your prayers.","T":"One more thing: please prepare a guest room for me, because I hope to be given back to you through your prayers."},
    "23": {"L":"Epaphras, my fellow prisoner in Christ Jesus, greets you,","M":"Epaphras, my fellow prisoner in Christ Jesus, sends you greetings.","T":"Epaphras, my fellow prisoner for Christ Jesus, sends his greetings."},
    "24": {"L":"as do Mark, Aristarchus, Demas, Luke, my fellow workers.","M":"And so do Mark, Aristarchus, Demas and Luke, my fellow workers.","T":"So do Mark, Aristarchus, Demas, and Luke—my fellow workers."},
    "25": {"L":"The grace of the Lord Jesus Christ be with your spirit.","M":"The grace of the Lord Jesus Christ be with your spirit.","T":"May the grace of the Lord Jesus Christ be with you all."}
  }
})

# ── 2 JOHN ───────────────────────────────────────────────────────────────
write_book('2john', {
  "1": {
    "1": {"L":"The elder to the elect lady and her children, whom I love in truth—and not I only, but also all who have known the truth—","M":"The elder, To the lady chosen by God and to her children, whom I love in the truth—and not I only, but also all who know the truth—","T":"I, the elder, am writing to the chosen lady and her children. I love all of you genuinely—and so does everyone who knows the truth—"},
    "2": {"L":"because of the truth that remains in us, and will be with us forever:","M":"because of the truth, which lives in us and will be with us forever:","T":"because of the truth that lives in us and will be with us forever."},
    "3": {"L":"Grace, mercy, and peace will be with us from God the Father and from Jesus Christ, the Son of the Father, in truth and love.","M":"Grace, mercy and peace from God the Father and from Jesus Christ, the Father's Son, will be with us in truth and love.","T":"Grace, mercy, and peace will be ours, given by God the Father and Jesus Christ, the Father's Son, through truth and love."},
    "4": {"L":"I rejoiced greatly because I have found some of your children walking in the truth, just as we received commandment from the Father.","M":"It has given me great joy to find some of your children walking in the truth, just as the Father commanded us.","T":"I was overjoyed to find some of your children living in the truth, just as the Father has commanded us."},
    "5": {"L":"And now I ask you, dear lady—not as though writing to you a new commandment, but one we have had from the beginning—that we love one another.","M":"And now, dear lady, I am not writing you a new command but one we have had from the beginning. I ask that we love one another.","T":"And now, dear lady, I want to remind you of something—this isn't a new command, just the one we have always had: that we love one another."},
    "6": {"L":"And this is love: that we walk according to his commandments. This is the commandment, just as you have heard from the beginning, so that you should walk in it.","M":"And this is love: that we walk in obedience to his commands. As you have heard from the beginning, his command is that you walk in love.","T":"And this is what love means: that we live according to his commands. And the command—as you've known from the beginning—is that you live in love."},
    "7": {"L":"For many deceivers have gone out into the world, those who do not confess that Jesus Christ is coming in the flesh. This is the deceiver and the antichrist.","M":"I say this because many deceivers, who do not acknowledge Jesus Christ as coming in the flesh, have gone out into the world. Any such person is the deceiver and the antichrist.","T":"Watch out—many deceivers have gone out into the world. They deny that Jesus Christ came as a real human being. Anyone like this is a deceiver and an antichrist."},
    "8": {"L":"Watch yourselves, so that you do not lose what we have worked for, but may receive a full reward.","M":"Watch out that you do not lose what we have worked for, but that you may be rewarded fully.","T":"Be careful that you don't throw away what we have worked for—you want to receive your full reward."},
    "9": {"L":"Everyone who goes on ahead and does not remain in the teaching of Christ does not have God; the one who remains in the teaching has both the Father and the Son.","M":"Anyone who runs ahead and does not continue in the teaching of Christ does not have God; whoever continues in the teaching has both the Father and the Son.","T":"Anyone who goes beyond and does not remain in the teaching of Christ does not have God. But whoever remains in that teaching has both the Father and the Son."},
    "10": {"L":"If anyone comes to you and does not bring this teaching, do not receive him into your house and do not give him a greeting,","M":"If anyone comes to you and does not bring this teaching, do not take them into your house or welcome them.","T":"If someone comes to you who does not hold to this teaching, don't invite them in or welcome them."},
    "11": {"L":"for the one who greets him shares in his evil works.","M":"Anyone who welcomes them shares in their wicked work.","T":"Anyone who welcomes them becomes a partner in their evil work."},
    "12": {"L":"Though I have much to write to you, I do not wish to do so with paper and ink; but I hope to come to you and speak face to face, so that our joy may be made full.","M":"I have much to write to you, but I do not want to use paper and ink. Instead, I hope to visit you and talk with you face to face, so that our joy may be complete.","T":"I have much more to say to you, but I don't want to put it in writing. I hope to come and talk with you in person—that will make our joy complete."},
    "13": {"L":"The children of your elect sister greet you.","M":"The children of your sister, who is chosen by God, send their greetings.","T":"The children of your sister—God's chosen one—send their love."}
  }
})

# ── 3 JOHN ───────────────────────────────────────────────────────────────
write_book('3john', {
  "1": {
    "1": {"L":"The elder to the beloved Gaius, whom I love in truth.","M":"The elder, To my dear friend Gaius, whom I love in the truth.","T":"I, the elder, am writing to my dear friend Gaius, whom I love in truth."},
    "2": {"L":"Beloved, I pray that in all things you may prosper and be in health, even as your soul prospers.","M":"Dear friend, I pray that you may enjoy good health and that all may go well with you, even as your soul is getting along well.","T":"Dear friend, I hope everything is going well with you and that you are in good health—just as you are thriving spiritually."},
    "3": {"L":"For I rejoiced greatly when brothers came and testified about your truth, as you walk in the truth.","M":"It gave me great joy when some believers came and testified about your faithfulness to the truth, telling how you continue to walk in it.","T":"I was overjoyed when fellow believers came and told me how faithfully you are walking in the truth."},
    "4": {"L":"I have no greater joy than this: to hear that my children are walking in the truth.","M":"I have no greater joy than to hear that my children are walking in the truth.","T":"Nothing brings me more joy than hearing that my spiritual children are walking in the truth."},
    "5": {"L":"Beloved, you act faithfully in whatever you do for the brothers, even though they are strangers to you,","M":"Dear friend, you are faithful in what you are doing for the brothers and sisters, even though they are strangers to you.","T":"Dear friend, you are doing a faithful work by caring for the traveling believers, even those you've never met."},
    "6": {"L":"who bore witness to your love before the church. You will do well to send them on their way worthily of God.","M":"They have told the church about your love. Please send them on their way in a manner that honors God.","T":"They've told the whole church about your love. Please help them on their journey in a way that is worthy of God."},
    "7": {"L":"For they went out for the sake of the Name, accepting nothing from the Gentiles.","M":"It was for the sake of the Name that they went out, receiving no help from the pagans.","T":"They set out to serve God and won't accept any support from unbelievers."},
    "8": {"L":"Therefore we ought to support such men, so that we may be fellow workers with the truth.","M":"We ought therefore to show hospitality to such people so that we may work together for the truth.","T":"We have a responsibility to support people like these—so that we can be fellow workers with the truth."},
    "9": {"L":"I wrote something to the church, but Diotrephes, who loves to be first among them, does not accept what we say.","M":"I wrote to the church, but Diotrephes, who loves to be first, will not welcome us.","T":"I wrote to the church, but Diotrephes—who loves to be in charge—won't have anything to do with us."},
    "10": {"L":"Therefore, if I come, I will call attention to what he is doing, spreading malicious nonsense about us. And not being content with that, he himself refuses to receive the brothers, and he hinders those who want to do so and puts them out of the church.","M":"So when I come, I will call attention to what he is doing, spreading malicious nonsense about us. Not satisfied with that, he even refuses to welcome other believers. He also stops those who want to do so and puts them out of the church.","T":"If I come, I will expose what he's doing—spreading lies about us. And on top of that, he refuses to welcome the visiting believers. He even tries to stop those who want to welcome them and throws them out of the church!"},
    "11": {"L":"Beloved, do not imitate what is evil but what is good. The one who does good is from God; the one who does evil has not seen God.","M":"Dear friend, do not imitate what is evil but what is good. Anyone who does what is good is from God. Anyone who does what is evil has not seen God.","T":"Dear friend, don't follow bad examples—follow good ones. Those who do good belong to God; those who do evil have never known God."},
    "12": {"L":"Demetrius has been testified to by all, and by the truth itself. We also testify, and you know that our testimony is true.","M":"Demetrius is well spoken of by everyone—and even by the truth itself. We also speak well of him, and you know that our testimony is true.","T":"Everyone speaks well of Demetrius—the truth itself commends him. And so do I—you know my testimony is reliable."},
    "13": {"L":"I had many things to write to you, but I do not wish to write them to you with ink and pen.","M":"I have much to write you, but I do not want to do so with pen and ink.","T":"I have much more to say, but I don't want to put it all in writing."},
    "14": {"L":"But I hope to see you soon, and we will speak face to face. Peace to you. The friends greet you. Greet the friends by name.","M":"I hope to see you soon, and we will talk face to face. Peace to you. The friends here send their greetings. Greet the friends there by name.","T":"I hope to see you soon, and then we can talk in person. Peace to you! The friends here send their love. Please greet each of the friends there by name."}
  }
})

# ── JUDE ─────────────────────────────────────────────────────────────────
write_book('jude', {
  "1": {
    "1": {"L":"Jude, a servant of Jesus Christ and brother of James, to those who are called, beloved in God the Father and kept for Jesus Christ:","M":"Jude, a servant of Jesus Christ and a brother of James, To those who have been called, who are loved in God the Father and kept for Jesus Christ:","T":"I, Jude, am a servant of Jesus Christ and a brother of James. I am writing to all who have been called by God the Father—loved by him and kept safe for Jesus Christ."},
    "2": {"L":"May mercy and peace and love be multiplied to you.","M":"Mercy, peace and love be yours in abundance.","T":"May mercy, peace, and love be lavished on you."},
    "3": {"L":"Beloved, while making every effort to write to you about our common salvation, I found it necessary to write to you and appeal to you to contend earnestly for the faith that was once for all delivered to the saints.","M":"Dear friends, although I was very eager to write to you about the salvation we share, I felt compelled to write and urge you to contend for the faith that was once for all entrusted to God's holy people.","T":"Dear friends, I was fully intending to write to you about the salvation we share together—but I felt I had to write urgently instead, to urge you to fight hard for the faith that was entrusted, once and for all, to God's people."},
    "4": {"L":"For certain men have crept in unnoticed, those who were long ago written about for this condemnation—ungodly men who pervert the grace of our God into licentiousness and deny our only Master and Lord, Jesus Christ.","M":"For certain individuals whose condemnation was written about long ago have secretly slipped in among you. They are ungodly people, who pervert the grace of our God into a license for immorality and deny Jesus Christ our only Sovereign and Lord.","T":"This is urgent because certain people have secretly slipped into your community—people whose judgment was written down long ago. These ungodly individuals twist God's grace into a license for sin and deny Jesus Christ, our only Master and Lord."},
    "5": {"L":"Now I want to remind you, though you know everything, that the Lord, having saved a people out of Egypt, afterward destroyed those who did not believe.","M":"Though you already know all this, I want to remind you that the Lord at one time delivered his people out of Egypt, but later destroyed those who did not believe.","T":"Even though you already know all this, I want to remind you: the Lord rescued his people out of Egypt, but later destroyed those who refused to believe."},
    "6": {"L":"And the angels who did not keep their own domain but abandoned their proper dwelling—these he has kept in eternal chains under deep darkness for the judgment of the great day.","M":"And the angels who did not keep their positions of authority but abandoned their proper dwelling—these he has kept in darkness, bound with everlasting chains for judgment on the great Day.","T":"And the angels who abandoned their own positions of authority and left their proper home—God has kept them in eternal chains in deep darkness, waiting for the judgment of the great day."},
    "7": {"L":"In the same way, Sodom and Gomorrah and the surrounding cities, which in the same manner as these indulged in sexual immorality and went after other flesh, are exhibited as an example by undergoing the punishment of eternal fire.","M":"In a similar way, Sodom and Gomorrah and the surrounding towns gave themselves up to sexual immorality and perversion. They serve as an example of those who suffer the punishment of eternal fire.","T":"Similarly, Sodom and Gomorrah and the surrounding towns gave themselves over to sexual immorality and unnatural desire. They stand as a permanent warning—suffering the punishment of eternal fire."},
    "8": {"L":"Yet in the same way, these dreamers also defile the flesh, reject authority, and blaspheme the glorious ones.","M":"In the very same way, on the strength of their dreams these ungodly people pollute their own bodies, reject authority and heap abuse on celestial beings.","T":"These people are the same—they are dreamers who pollute their own bodies, despise authority, and mock the glorious ones."},
    "9": {"L":"But Michael the archangel, when disputing with the devil he argued about the body of Moses, did not dare to bring a slanderous judgment against him, but said: 'May the Lord rebuke you!'","M":"But even the archangel Michael, when he was disputing with the devil about the body of Moses, did not himself dare to condemn him for slander but said, 'The Lord rebuke you!'","T":"But even Michael the archangel, when he was arguing with the devil over the body of Moses, didn't dare to slander him. He simply said, 'The Lord rebuke you!'"},
    "10": {"L":"But these men speak evil of what they do not know, and what they know by instinct—like irrational animals—by these things they are being destroyed.","M":"Yet these people slander whatever they do not understand, and the very things they do understand by instinct—as irrational animals do—will destroy them.","T":"But these people mock anything they don't understand, and the things they do understand—by animal instinct—are the very things that destroy them."},
    "11": {"L":"Woe to them! For they have gone in the way of Cain, and for wages they have rushed into the error of Balaam, and they have perished in the rebellion of Korah.","M":"Woe to them! They have taken the way of Cain; they have rushed for profit into Balaam's error; they have been destroyed in Korah's rebellion.","T":"What terrible things await them! They have walked the path of Cain, rushed headlong into Balaam's error for financial gain, and been destroyed by Korah's kind of rebellion."},
    "12": {"L":"These are hidden reefs at your love feasts, when they feast together without fear, shepherding themselves; waterless clouds carried along by winds; fruitless late-autumn trees, having died twice, uprooted;","M":"These people are blemishes at your love feasts, eating with you without the slightest qualm—shepherds who feed only themselves. They are clouds without rain, blown along by the wind; autumn trees, without fruit and uprooted—twice dead.","T":"These people are dangerous blemishes at your fellowship meals—eating alongside you without a care, taking care only of themselves. They are clouds that blow by without giving any rain; autumn trees stripped of fruit and pulled up by the roots—dead twice over."},
    "13": {"L":"wild waves of the sea, foaming up their own shame; wandering stars, for whom the gloom of deep darkness has been reserved forever.","M":"They are wild waves of the sea, foaming up their shame; wandering stars, for whom blackest darkness has been reserved forever.","T":"They are wild ocean waves that churn up only their own shame. They are wandering stars, destined for the blackest darkness forever."},
    "14": {"L":"And to these also Enoch, the seventh from Adam, prophesied, saying: 'Behold, the Lord came with his holy myriads,","M":"Enoch, the seventh from Adam, prophesied about them: 'See, the Lord is coming with thousands upon thousands of his holy ones","T":"Enoch, the seventh generation from Adam, prophesied about these people: 'Look! The Lord is coming with tens of thousands of his holy ones—"},
    "15": {"L":"to execute judgment against all, and to convict all the ungodly of all their ungodly works that they have done in an ungodly way, and of all the harsh things that ungodly sinners have spoken against him.'","M":"to judge everyone, and to convict all of them of all the ungodly acts they have committed in their ungodliness, and of all the defiant words ungodly sinners have spoken against him.'","T":"to carry out judgment on everyone—to convict every person of every ungodly act they have committed in their ungodliness, and for every defiant word that ungodly sinners have spoken against him.'"},
    "16": {"L":"These are grumblers, malcontents, going according to their desires; and their mouth speaks arrogant things, flattering people for the sake of their own advantage.","M":"These people are grumblers and faultfinders; they follow their own evil desires; they boast about themselves and flatter others for their own advantage.","T":"These people are constant complainers who do whatever they feel like doing. They boast loudly about themselves and flatter others whenever it benefits them."},
    "17": {"L":"But you, beloved, remember the words spoken beforehand by the apostles of our Lord Jesus Christ,","M":"But, dear friends, remember what the apostles of our Lord Jesus Christ foretold.","T":"But you, dear friends, remember what the apostles of our Lord Jesus Christ said would happen."},
    "18": {"L":"that they were saying to you: 'In the last time there will be mockers following after their own ungodly desires.'","M":"They said to you, 'In the last times there will be scoffers who will follow their own ungodly desires.'","T":"They warned you: 'In the last days, mockers will arise who follow their own ungodly desires.'"},
    "19": {"L":"These are the ones who create divisions, worldly people, devoid of the Spirit.","M":"These are the people who divide you, who follow mere natural instincts and do not have the Spirit.","T":"These are the people who create divisions—driven by natural instincts with no share in the Spirit."},
    "20": {"L":"But you, beloved, building yourselves up in your most holy faith, praying in the Holy Spirit,","M":"But you, dear friends, by building yourselves up in your most holy faith and praying in the Holy Spirit,","T":"But you, dear friends, must build yourselves up in your most holy faith, praying in the Holy Spirit."},
    "21": {"L":"keep yourselves in the love of God, waiting anxiously for the mercy of our Lord Jesus Christ to eternal life.","M":"keep yourselves in God's love as you wait for the mercy of our Lord Jesus Christ to bring you to eternal life.","T":"Keep yourselves in God's love while you wait for the mercy of our Lord Jesus Christ—the mercy that leads to eternal life."},
    "22": {"L":"And have mercy on those who are doubting;","M":"Be merciful to those who doubt;","T":"Show mercy to those who are wavering in their faith."},
    "23": {"L":"save others by snatching them out of the fire; and on others have mercy with fear, hating even the garment stained by the flesh.","M":"save others by snatching them from the fire; to others show mercy, mixed with fear—hating even the clothing stained by corrupted flesh.","T":"Pull others out of the fire and save them. And for others, show mercy mixed with caution—hating even the clothing contaminated by their sinful living."},
    "24": {"L":"Now to him who is able to keep you from stumbling and to present you blameless before the presence of his glory with great joy—","M":"To him who is able to keep you from stumbling and to present you before his glorious presence without fault and with great joy—","T":"Now to the one who has the power to keep you from falling and to bring you into his glorious presence—spotless and filled with joy—"},
    "25": {"L":"to the only God our Savior, through Jesus Christ our Lord, be glory, majesty, dominion, and authority, before all time and now and forever. Amen.","M":"to the only God our Savior be glory, majesty, power and authority, through Jesus Christ our Lord, before all ages, now and forevermore! Amen.","T":"to the only God our Savior, through Jesus Christ our Lord—be glory, majesty, power, and authority, before all time, now and forever. Amen."}
  }
})

print('\nPhase 1 complete: Philemon, 2 John, 3 John, Jude')
